// DB 집계 → 자체완결 HTML 리포트 조립 (외부 의존 0, 라이트/다크).
const esc = (s)=> String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const S = $('요약').first().json;
const tech = $('기술 TOP').all().map(i=>i.json);
const career = $('경력 분포').all().map(i=>i.json);
const src = $('소스별').all().map(i=>i.json);
const maxT = Math.max(1, ...tech.map(t=>Number(t.cnt)));
const maxC = Math.max(1, ...career.map(c=>Number(c.cnt)));
const now = new Date(); const pad=n=>String(n).padStart(2,'0');
const ts = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}`;
const srcName = s => s==='wanted'?'원티드':s==='jumpit'?'점프잇':s;
const techBars = tech.map(t=>`<div class="row"><div class="lbl" title="${esc(t.tech)}">${esc(t.tech)}</div><div class="track"><div class="fill" style="width:${(t.cnt/maxT*100).toFixed(1)}%"></div></div><div class="val">${t.cnt}</div></div>`).join('');
const careerBars = career.map(c=>`<div class="row"><div class="lbl">${esc(c.bucket)}</div><div class="track"><div class="fill fill2" style="width:${(c.cnt/maxC*100).toFixed(1)}%"></div></div><div class="val">${c.cnt}</div></div>`).join('');
const srcCards = src.map(s=>`<div class="scard"><div class="sname">${esc(srcName(s.source))}</div><div class="snum">${s.cnt}<span>건</span></div><div class="ssub">평균 요구경력 ${s.avg_career==null?'-':s.avg_career}년</div></div>`).join('');
const card = (k,v,u)=>`<div class="card"><div class="k">${k}</div><div class="v">${v}${u?`<span> ${u}</span>`:''}</div></div>`;
const html = `<!doctype html>
<html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>채용 시장 리포트</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
:root{--bg:#f6f7fb;--card:#fff;--ink:#1a1a2e;--sub:#6b7280;--line:#e5e7eb;--accent:#6366f1;--accent2:#8b5cf6;--track:#eef0f6}
@media(prefers-color-scheme:dark){:root{--bg:#0f1117;--card:#1a1d29;--ink:#e8eaf0;--sub:#9096a8;--line:#262a38;--accent:#818cf8;--accent2:#a78bfa;--track:#232735}}
body{background:var(--bg);color:var(--ink);font-family:-apple-system,BlinkMacSystemFont,'Segoe UI','Malgun Gothic',sans-serif;line-height:1.5;padding:32px 16px}
.wrap{max-width:920px;margin:0 auto}
header{margin-bottom:26px}
header h1{font-size:28px;font-weight:800;background:linear-gradient(90deg,var(--accent),var(--accent2));-webkit-background-clip:text;background-clip:text;color:transparent}
header p{color:var(--sub);font-size:14px;margin-top:6px}
.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:14px;margin-bottom:26px}
.card{background:var(--card);border:1px solid var(--line);border-radius:14px;padding:18px}
.card .k{color:var(--sub);font-size:13px}
.card .v{font-size:26px;font-weight:800;margin-top:4px}
.card .v span{font-size:13px;font-weight:600;color:var(--sub)}
.panel{background:var(--card);border:1px solid var(--line);border-radius:16px;padding:22px;margin-bottom:22px}
.panel h2{font-size:17px;font-weight:700;margin-bottom:16px}
.row{display:grid;grid-template-columns:130px 1fr 46px;align-items:center;gap:12px;margin-bottom:9px}
.lbl{font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.track{background:var(--track);border-radius:8px;height:22px;overflow:hidden}
.fill{height:100%;border-radius:8px;background:linear-gradient(90deg,var(--accent),var(--accent2));min-width:3px}
.fill2{background:linear-gradient(90deg,#10b981,#34d399)}
.val{font-size:13px;font-weight:700;text-align:right;color:var(--sub)}
.scards{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:14px}
.scard{background:var(--track);border-radius:12px;padding:16px;text-align:center}
.sname{font-weight:700;font-size:15px}
.snum{font-size:30px;font-weight:800;margin:6px 0}
.snum span{font-size:14px;color:var(--sub);font-weight:600}
.ssub{font-size:13px;color:var(--sub)}
footer{color:var(--sub);font-size:12px;text-align:center;margin-top:22px}
</style></head><body><div class="wrap">
<header><h1>채용 시장 분석 리포트</h1><p>수집 공고 ${S.total}건 기준 · AI/개발 직군 · ${S.from_date} ~ ${S.to_date}</p></header>
<section class="cards">${card('총 공고',S.total,'건')}${card('원티드 / 점프잇',`${S.wanted} / ${S.jumpit}`)}${card('평균 요구경력',S.avg_career==null?'-':S.avg_career,'년')}${card('기술 종류',S.tech_kinds,'종')}</section>
<section class="panel"><h2>🔧 기술스택 수요 TOP 15</h2>${techBars}</section>
<section class="panel"><h2>👤 요구 경력 분포</h2>${careerBars}</section>
<section class="panel"><h2>🌐 소스별 비교</h2><div class="scards">${srcCards}</div></section>
<footer>생성 ${ts} · n8n 08 시장 리포트 워크플로우 · 로컬 자동 생성</footer>
</div></body></html>`;
const binary = await this.helpers.prepareBinaryData(Buffer.from(html,'utf-8'),'market-report.html','text/html');
return [{ json:{ filename:'market-report.html', bytes: html.length }, binary:{ data: binary } }];
